// Acumula os leads desta página e decide se há próxima.
// A API v4 do Kommo devolve { _embedded: { leads: [...] }, _links: { next?: {} } }
const inState = $('2. Init (page=1)').first().json;
const prevAcc = JSON.parse($json.acc ?? inState.acc ?? '[]');
const body = $json;
const leads = body?._embedded?.leads ?? [];
const acc = prevAcc.concat(leads);
const hasNext = !!(body?._links && body._links.next);
const page = ($json.page ?? inState.page ?? 1);
return [{ json: { acc: JSON.stringify(acc), page: page + 1, hasNext, count: acc.length } }];

// ============================================================
// NORMALIZAÇÃO — ajustada aos campos REAIS do Kommo (Energy Solar RJ)
// Mapeia custom fields por NOME. Campos ausentes viram null (ok).
// ============================================================
const raw = JSON.parse($json.acc);

const FIELD_MAP = {
  'Origem': 'origin',
  'Produto': 'product',
  'Consumo [R$]': 'consumo',
  'Local': 'local',
  'Aumentar Consumo': 'aumentarConsumo',
  'Telhado': 'telhado',
  'Método de pagamento': 'payment',
  'Tipo de cliente': 'clientType',
  'Endereço': 'endereco',
  'Consultor [Visita]': 'consultor',
};
const DATE_MAP = {
  'Agendamento [Proposta]': 'proposalAt',
  'Agendamento [Visita]': 'visitAt',
  'Data Resgate [Futuramente]': 'rescueAt',
};
// AJUSTE com os IDs reais (rode GET /api/v4/leads/pipelines):
const WON_STAGE_IDS = [142];
const LOST_STAGE_IDS = [143];

const iso = (u) => u ? new Date(u * 1000).toISOString() : null;
function cf(lead, name) {
  const f = (lead.custom_fields_values || []).find(x => x.field_name === name);
  if (!f || !f.values || !f.values.length) return null;
  return f.values[0].value ?? null;
}

const out = raw.map((lead) => {
  const fields = {};
  for (const [n, k] of Object.entries(FIELD_MAP)) fields[k] = cf(lead, n);
  const dates = {};
  for (const [n, k] of Object.entries(DATE_MAP)) { const v = cf(lead, n); dates[k] = v ? iso(Number(v)) : null; }

  let status = 'open';
  if (WON_STAGE_IDS.includes(lead.status_id)) status = 'won';
  else if (LOST_STAGE_IDS.includes(lead.status_id)) status = 'lost';
  if (lead.closed_at && lead.price > 0 && status === 'open') status = 'won';

  return {
    id: lead.id,
    name: (lead.name || ('Lead #' + lead.id)).trim(),
    pipelineId: lead.pipeline_id,
    stageId: lead.status_id,
    status,
    origin: fields.origin ?? null,
    product: fields.product ?? null,
    value: lead.price || null,
    createdAt: iso(lead.created_at),
    updatedAt: iso(lead.updated_at),
    utmCampaign: cf(lead, 'utm_campaign') ?? null,
    utmSource: cf(lead, 'utm_source') ?? null,
    proposalAt: dates.proposalAt,
    visitAt: dates.visitAt,
    rescueAt: dates.rescueAt,
    lossReason: lead.loss_reason_id ? String(lead.loss_reason_id) : null,
    fields: {
      consumo: fields.consumo,
      local: fields.local,
      telhado: fields.telhado,
      payment: fields.payment,
      clientType: fields.clientType,
      endereco: fields.endereco,
      consultor: fields.consultor,
      aumentarConsumo: fields.aumentarConsumo,
    },
  };
});

const jsonString = JSON.stringify(out);
const base64 = Buffer.from(jsonString, 'utf8').toString('base64');
return [{ json: { totalLeads: out.length, base64, jsonString } }];

// pega o sha do arquivo atual (necessário para atualizar).
// se o arquivo ainda não existe (404), sha fica undefined e o PUT cria.
const sha = $json.sha; // presente quando o arquivo já existe
const base64 = $('5. Normalizar → base64').first().json.base64;
const total = $('5. Normalizar → base64').first().json.totalLeads;
return [{ json: { sha: sha ?? null, base64, total } }];
